<?php namespace App\Services\Finance; use App\Data\Payments\PaymentProviderResult; use App\Models\{Order,PaymentRecord,PaymentWebhookEvent,User}; use Illuminate\Support\Str;
class PaymentService{public function __construct(private DisabledPaymentProvider $provider,private PaymentNumberGenerator $numbers,private PaymentReadinessService $readiness){}public function createDraftPaymentForOrder(Order $order,User $actor):PaymentRecord{$q=$order->latestPriceQuote();$p=PaymentRecord::create(['payment_number'=>$this->numbers->payment(),'order_id'=>$order->id,'customer_id'=>$order->customer_id,'provider'=>'disabled','status'=>'draft','currency'=>$q?->currency??$order->currency,'amount'=>$q?->total,'idempotency_key'=>(string)Str::uuid(),'requested_by_id'=>$actor->id]);$this->event($p,$actor,'created','Draft payment record created.');return $p;}public function requestPaymentIntent(PaymentRecord $p,User $a):PaymentProviderResult{return $this->blocked($p,$a,'intent_requested',$this->provider->createPaymentIntent($p));}public function capturePayment(PaymentRecord $p,User $a):PaymentProviderResult{return $this->blocked($p,$a,'captured',$this->provider->capture($p));}public function refundPayment(PaymentRecord $p,User $a,string $amount,string $reason):PaymentProviderResult{return $this->blocked($p,$a,'refunded',$this->provider->refund($p,$amount,$reason));}public function recordWebhook(string $provider,array $payload,array $headers):PaymentWebhookEvent{return PaymentWebhookEvent::create(['provider'=>$provider,'payload_hash'=>hash('sha256',json_encode($payload)),'status'=>'rejected','received_at'=>now(),'failure_reason'=>'No configured webhook adapter.']);}private function blocked(PaymentRecord $p,User $a,string $requested,PaymentProviderResult $r):PaymentProviderResult{$p->update(['status'=>'provider_disabled','failure_reason'=>$r->message]);$this->event($p,$a,'provider_disabled',$r->message,['requested_action'=>$requested]);return $r;}private function event(PaymentRecord $p,User $a,string $type,string $description,array $metadata=[]):void{$p->events()->create(['order_id'=>$p->order_id,'actor_id'=>$a->id,'event_type'=>$type,'provider'=>$p->provider,'idempotency_key'=>$p->idempotency_key,'description'=>$description,'metadata'=>$metadata,'created_at'=>now()]);}}
